import React, { useEffect, useState, useCallback } from 'react';
import axios from 'axios';
import { useAuth, authHeader } from '../hooks/useAuth';
import {
  AppBar, Toolbar, Typography, Button, Box, Container,
  Grid, Card, CardContent, TextField, MenuItem, Select,
  InputLabel, FormControl, Tabs, Tab, Table, TableBody,
  TableCell, TableContainer, TableHead, TableRow, Paper,
  IconButton, Alert, Chip
} from '@mui/material';
import DeleteIcon from '@mui/icons-material/Delete';
import AddIcon from '@mui/icons-material/Add';
import { Divider } from '@mui/material';

const API = 'http://localhost:3001/api';

interface Movimiento {
  id: number;
  monto: number;
  descripcion: string;
  fecha: string;
  categoria_id?: number;
  categoria_nombre?: string;
}

interface Resumen {
  totalIngresos: number;
  totalGastos: number;
  balance: number;
}

interface Categoria {
  id: number;
  nombre: string;
}

const Dashboard: React.FC = () => {
  const { username, logout } = useAuth();
  const [tab, setTab] = useState(0);
  const [ingresos, setIngresos] = useState<Movimiento[]>([]);
  const [gastos, setGastos] = useState<Movimiento[]>([]);
  const [categorias, setCategorias] = useState<Categoria[]>([]);
  const [resumen, setResumen] = useState<Resumen>({ totalIngresos: 0, totalGastos: 0, balance: 0 });
  const [success, setSuccess] = useState('');

  // Formulario ingreso
  const [montoI, setMontoI] = useState('');
  const [descI, setDescI] = useState('');
  const [fechaI, setFechaI] = useState(new Date().toISOString().split('T')[0]);

  // Formulario gasto
  const [montoG, setMontoG] = useState('');
  const [descG, setDescG] = useState('');
  const [fechaG, setFechaG] = useState(new Date().toISOString().split('T')[0]);
  const [catG, setCatG] = useState('');

  // Filtros
  const [filtroDesde, setFiltroDesde] = useState('');
  const [filtroHasta, setFiltroHasta] = useState('');
  const [filtroCategoria, setFiltroCategoria] = useState('');

  //efectos
  const [ingresoBrilla, setIngresoBrilla] = useState(false);
  const [gastoBrilla, setGastoBrilla] = useState(false);

  // Suma de los gastos por categoría
  const gastosPorCategoria = gastos.reduce((acc: Record<string, number>, g) => {
  const cat = g.categoria_nombre || 'Sin categoría';
  acc[cat] = (acc[cat] || 0) + Number(g.monto); 
  return acc;
  }, {});

  const etiquetas = Object.keys(gastosPorCategoria);
  const valores = Object.values(gastosPorCategoria);

  const totalGastos = valores.reduce((a, b) => a + b, 0);
  const porcentajes = valores.map(v => (v / totalGastos) * 100);

 //Meses de las Barras
 const [anioSeleccionado, setAnioSeleccionado] = useState(new Date().getFullYear());

const gastosDelAnio = gastos.filter(g => {
  const fecha = new Date(g.fecha);
  return fecha.getFullYear() === anioSeleccionado;
});

const gastosPorMes = React.useMemo(() => {
  const meses = Array(12).fill(0);

  gastos.forEach(g => {
    const fecha = new Date(g.fecha);

    if (fecha.getFullYear() === anioSeleccionado) {
      const mes = fecha.getMonth();
      const monto = parseFloat(g.monto as any) || 0;

      meses[mes] += monto;
    }
  });

  return meses;
}, [gastos, anioSeleccionado]);

const max = Math.max(...gastosPorMes, 1);

const meses = [
  'Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun',
  'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'
];

// Barras para ingresos
const ingresosPorMes = React.useMemo(() => {
  const meses = Array(12).fill(0);

  ingresos.forEach(i => {
    const fecha = new Date(i.fecha);

    if (fecha.getFullYear() === anioSeleccionado) {
      const mes = fecha.getMonth();
      const monto = parseFloat(i.monto as any) || 0;

      meses[mes] += monto;
    }
  });

  return meses;
}, [ingresos, anioSeleccionado]);

const maxIngresos = Math.max(...ingresosPorMes, 1);


  const fetchData = useCallback(async () => {
    const [ingRes, gasRes, resRes, catRes] = await Promise.all([
      axios.get(`${API}/ingresos`, authHeader()),
      axios.get(`${API}/gastos`, authHeader()),
      axios.get(`${API}/resumen`, authHeader()),
      axios.get(`${API}/categorias`, authHeader()),
    ]);
    setIngresos(ingRes.data);
    setGastos(gasRes.data);
    setResumen(resRes.data);
    setCategorias(catRes.data);
  }, []);

  useEffect(() => { fetchData(); }, [fetchData]);

  const addIngreso = async (e: React.FormEvent) => {
    e.preventDefault();
    await axios.post(`${API}/ingresos`, { monto: montoI, descripcion: descI, fecha: fechaI }, authHeader());
    setMontoI(''); setDescI(''); setFechaI(new Date().toISOString().split('T')[0]);
    setSuccess('Ingreso agregado'); fetchData(); 

    setIngresoBrilla(true);
  setTimeout(() => setIngresoBrilla(false), 400); 

 setTimeout(() => setSuccess(''), 3000);
  };

  const addGasto = async (e: React.FormEvent) => {
    e.preventDefault();

    if (parseFloat(montoG) > resumen.balance) {
    setSuccess('');
    alert('No puedes gastar más de tu balance disponible'); 
    return; 
  }

    await axios.post(`${API}/gastos`, { monto: montoG, descripcion: descG, fecha: fechaG, categoria_id: catG }, authHeader());
    setMontoG(''); setDescG(''); setFechaG(new Date().toISOString().split('T')[0]); setCatG('');
    setSuccess('Gasto agregado'); fetchData();


  setGastoBrilla(true);
  setTimeout(() => setGastoBrilla(false), 400); 

    setTimeout(() => setSuccess(''), 3000);
  };

  const deleteIngreso = async (id: number) => {
    await axios.delete(`${API}/ingresos/${id}`, authHeader());
    fetchData();
  };

  const deleteGasto = async (id: number) => {
    await axios.delete(`${API}/gastos/${id}`, authHeader());
    fetchData();
  };

  const filtrarGastos = async () => {
    // FILTRO PARA GASTOS
  const gastoParams: any = {};
  if (filtroDesde) gastoParams.desde = filtroDesde;
  if (filtroHasta) gastoParams.hasta = filtroHasta;
  if (filtroCategoria) gastoParams.categoria_id = filtroCategoria;

  const [gastosRes, ingresosRes] = await Promise.all([
    axios.get(`${API}/gastos`, { headers: authHeader().headers, params: gastoParams }),
    axios.get(`${API}/ingresos`, { headers: authHeader().headers, params: {
      ...(filtroDesde && { desde: filtroDesde }),
      ...(filtroHasta && { hasta: filtroHasta })
    }})
  ]);

  setGastos(gastosRes.data);
  setIngresos(ingresosRes.data);
};

  const fmt = (n: number) => `$${n.toLocaleString('es-DO', { minimumFractionDigits: 2 })}`;

  return (
    <Box sx={{ minHeight: '100vh', bgcolor: '#f0f4f8' }}>
      <AppBar position="static">
        <Toolbar>
          <Typography variant="h6" sx={{ flexGrow: 1 }}>💰 Gastos Personales</Typography>
          <Typography variant="body2" sx={{ mr: 2 }}>Hola, {username}</Typography>
          <Button color="inherit" onClick={logout}>Cerrar Sesión</Button>
        </Toolbar>
      </AppBar>

      <Container maxWidth="lg" sx={{ mt: 4, pb: 4 }}>
        {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

        {/* TARJETAS DE RESUMEN */}
        <Grid container spacing={3} sx={{ mb: 4 }}>
          {[
            { label: 'Total Ingresos', value: resumen.totalIngresos, color: '#2e7d32' },
            { label: 'Total Gastos', value: resumen.totalGastos, color: '#c62828' },
            { label: 'Balance Disponible', value: resumen.balance, color: resumen.balance >= 0 ? '#1565c0' : '#c62828' },
          ].map((item) => (
            <Grid item xs={12} md={4} key={item.label}>
              <Card elevation={3}  sx={{        backgroundColor: item.label === 'Total Ingresos' && ingresoBrilla? '#e6f9ec' : item.label === 'Total Gastos' && gastoBrilla
                ? '#fde0e2' : '#fff', transition: ingresoBrilla || gastoBrilla ? 'none' : 'background-color 0.8s ease',
          }}>
                <CardContent sx={{ textAlign: 'center' }}>
                  <Typography variant="body2" color="text.secondary">{item.label}</Typography>
                  <Typography variant="h4" fontWeight="bold" sx={{ color: item.color }}>
                    {fmt(item.value)}
                  </Typography>
                </CardContent>
              </Card>
            </Grid>
          ))}
        </Grid>

        {/* TABS */}
        <Paper elevation={2}>
          <Tabs value={tab} onChange={(_, v) => setTab(v)} sx={{ borderBottom: 1, borderColor: 'divider' }}>
            <Tab label="Agregar Ingreso" />
            <Tab label="Agregar Gasto" />
            <Tab label="Movimientos" />
            <Tab label="Gráficas" />
          </Tabs>

          {/* TAB: AGREGAR INGRESO */}
          {tab === 0 && (
            <Box sx={{ p: 3 }}>
              <Typography variant="h6" gutterBottom>Nuevo Ingreso</Typography>
              <Box component="form" onSubmit={addIngreso}>
                <Grid container spacing={2}>
                  <Grid item xs={12} sm={4}>
                    <TextField fullWidth label="Monto" type="number" required value={montoI} onChange={e => setMontoI(e.target.value)} inputProps={{ min: 0, step: '0.01' }} />
                  </Grid>
                  <Grid item xs={12} sm={4}>
                    <TextField fullWidth label="Descripción" value={descI} onChange={e => setDescI(e.target.value)} />
                  </Grid>
                  <Grid item xs={12} sm={4}>
                    <TextField fullWidth label="Fecha" type="date" required value={fechaI} onChange={e => setFechaI(e.target.value)} InputLabelProps={{ shrink: true }} />
                  </Grid>
                </Grid>
                <Button type="submit" variant="contained" color="success" startIcon={<AddIcon />} sx={{ mt: 2 }}>
                  Agregar Ingreso
                </Button>
              </Box>

                            {/* Tabla Ingresos */}
              <Typography variant="subtitle1" fontWeight="bold" sx={{ mb: 1, color: '#2e7d32' }}>Ingresos</Typography>
              <TableContainer component={Paper} sx={{ mb: 3 }}>
                <Table size="small">
                  <TableHead sx={{ bgcolor: '#e8f5e9' }}>
                    <TableRow>
                      <TableCell>Fecha</TableCell>
                      <TableCell>Descripción</TableCell>
                      <TableCell align="right">Monto</TableCell>
                      <TableCell align="center">Eliminar</TableCell>
                    </TableRow>
                  </TableHead>
                  <TableBody>
                    {ingresos.length === 0 ? (
                      <TableRow><TableCell colSpan={4} align="center">Sin ingresos registrados</TableCell></TableRow>
                    ) : ingresos.slice(0, 5).map(i => (
                      <TableRow key={i.id}>
                        <TableCell>{i.fecha?.split('T')[0]}</TableCell>
                        <TableCell>{i.descripcion || '-'}</TableCell>
                        <TableCell align="right" sx={{ color: '#2e7d32', fontWeight: 'bold' }}>{fmt(i.monto)}</TableCell>
                        <TableCell align="center">
                          <IconButton size="small" onClick={() => deleteIngreso(i.id)} color="error"><DeleteIcon fontSize="small" /></IconButton>
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </TableContainer>
            </Box>
          )}

          {/* TAB: AGREGAR GASTO */}
          {tab === 1 && (
            <Box sx={{ p: 3 }}>
              <Typography variant="h6" gutterBottom>Nuevo Gasto</Typography>
              <Box component="form" onSubmit={addGasto}>
                <Grid container spacing={2}>
                  <Grid item xs={12} sm={3}>
                    <TextField fullWidth label="Monto" type="number" required value={montoG} onChange={e => setMontoG(e.target.value)} inputProps={{ min: 0, step: '0.01' }} />
                  </Grid>
                  <Grid item xs={12} sm={3}>
                    <TextField fullWidth label="Descripción" value={descG} onChange={e => setDescG(e.target.value)} />
                  </Grid>
                  <Grid item xs={12} sm={3}>
                    <TextField fullWidth label="Fecha" type="date" required value={fechaG} onChange={e => setFechaG(e.target.value)} InputLabelProps={{ shrink: true }} />
                  </Grid>
                  <Grid item xs={12} sm={3}>
                    <FormControl fullWidth required>
                      <InputLabel>Categoría</InputLabel>
                      <Select value={catG} label="Categoría" onChange={e => setCatG(e.target.value)}>
                        {categorias.map(c => <MenuItem key={c.id} value={c.id}>{c.nombre}</MenuItem>)}
                      </Select>
                    </FormControl>
                  </Grid>
                </Grid>
                <Button type="submit" variant="contained" color="error" startIcon={<AddIcon />} sx={{ mt: 2 }}>
                  Agregar Gasto
                </Button>
              </Box>

                            {/* Tabla Gastos */}
              <Typography variant="subtitle1" fontWeight="bold" sx={{ mb: 1, color: '#c62828' }}>Gastos</Typography>
              <TableContainer component={Paper}>
                <Table size="small">
                  <TableHead sx={{ bgcolor: '#ffebee' }}>
                    <TableRow>
                      <TableCell>Fecha</TableCell>
                      <TableCell>Descripción</TableCell>
                      <TableCell>Categoría</TableCell>
                      <TableCell align="right">Monto</TableCell>
                      <TableCell align="center">Eliminar</TableCell>
                    </TableRow>
                  </TableHead>
                  <TableBody>
                    {gastos.length === 0 ? (
                      <TableRow><TableCell colSpan={5} align="center">Sin gastos registrados</TableCell></TableRow>
                    ) : gastos.slice(0, 5).map(g => (
                      <TableRow key={g.id}>
                        <TableCell>{g.fecha?.split('T')[0]}</TableCell>
                        <TableCell>{g.descripcion || '-'}</TableCell>
                        <TableCell><Chip label={g.categoria_nombre || '-'} size="small" /></TableCell>
                        <TableCell align="right" sx={{ color: '#c62828', fontWeight: 'bold' }}>{fmt(g.monto)}</TableCell>
                        <TableCell align="center">
                          <IconButton size="small" onClick={() => deleteGasto(g.id)} color="error"><DeleteIcon fontSize="small" /></IconButton>
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </TableContainer>
            </Box>
          )}

          {/* TAB: MOVIMIENTOS */}
          {tab === 2 && (
            <Box sx={{ p: 3 }}>
              {/* Filtros */}
              <Typography variant="h6" gutterBottom>Filtrar Gastos</Typography>
              <Grid container spacing={2} sx={{ mb: 3 }}>
                <Grid item xs={12} sm={3}>
                  <TextField fullWidth label="Desde" type="date" value={filtroDesde} onChange={e => setFiltroDesde(e.target.value)} InputLabelProps={{ shrink: true }} />
                </Grid>
                <Grid item xs={12} sm={3}>
                  <TextField fullWidth label="Hasta" type="date" value={filtroHasta} onChange={e => setFiltroHasta(e.target.value)} InputLabelProps={{ shrink: true }} />
                </Grid>
                <Grid item xs={12} sm={3}>
                  <FormControl fullWidth>
                    <InputLabel>Categoría</InputLabel>
                    <Select value={filtroCategoria} label="Categoría" onChange={e => setFiltroCategoria(e.target.value as string)}>
                      <MenuItem value="">Todas</MenuItem>
                      {categorias.map(c => <MenuItem key={c.id} value={c.id}>{c.nombre}</MenuItem>)}
                    </Select>
                  </FormControl>
                </Grid>
                <Grid item xs={12} sm={3} sx={{ display: 'flex', alignItems: 'center' }}>
                  <Button variant="outlined" onClick={filtrarGastos} fullWidth>Filtrar</Button>
                </Grid>
              </Grid>

              {/* Tabla Ingresos */}
              <Typography variant="subtitle1" fontWeight="bold" sx={{ mb: 1, color: '#2e7d32' }}>Ingresos</Typography>
              <TableContainer component={Paper} sx={{ maxHeight: 400 }}>
                <Table stickyHeader size="small">
                  <TableHead sx={{ bgcolor: '#e8f5e9' }}>
                    <TableRow>
                      <TableCell sx={{mb: 1, color: '#2e7d32', bgcolor: '#e8f5e9'}}>Fecha</TableCell>
                      <TableCell sx={{mb: 1, color: '#2e7d32', bgcolor: '#e8f5e9'}}>Descripción</TableCell>
                      <TableCell sx={{mb: 1, color: '#2e7d32', bgcolor: '#e8f5e9'}} align="right">Monto</TableCell>
                      <TableCell sx={{mb: 1, color: '#2e7d32', bgcolor: '#e8f5e9'}} align="center">Eliminar</TableCell>
                    </TableRow>
                  </TableHead>
                  <TableBody>
                    {ingresos.length === 0 ? (
                      <TableRow><TableCell colSpan={4} align="center">Sin ingresos registrados</TableCell></TableRow>
                    ) : ingresos.map(i => (
                      <TableRow key={i.id}>
                        <TableCell>{i.fecha?.split('T')[0]}</TableCell>
                        <TableCell>{i.descripcion || '-'}</TableCell>
                        <TableCell align="right" sx={{ color: '#2e7d32', fontWeight: 'bold' }}>{fmt(i.monto)}</TableCell>
                        <TableCell align="center">
                          <IconButton size="small" onClick={() => deleteIngreso(i.id)} color="error"><DeleteIcon fontSize="small" /></IconButton>
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </TableContainer>

              {/* Tabla Gastos */}
              <Typography variant="subtitle1" fontWeight="bold" sx={{ mt:3, mb: 1, color: '#c62828' }}>Gastos</Typography>
              <TableContainer component={Paper} sx={{ maxHeight: 400 }}>
                <Table stickyHeader size="small">
                  <TableHead sx={{ bgcolor: '#ffebee' }}>
                    <TableRow>
                      <TableCell sx={{ mb: 1, color: '#c62828', bgcolor: '#ffebee' }}>Fecha</TableCell>
                      <TableCell sx={{ mb: 1, color: '#c62828', bgcolor: '#ffebee' }}>Descripción</TableCell>
                      <TableCell sx={{ mb: 1, color: '#c62828', bgcolor: '#ffebee' }}>Categoría</TableCell>
                      <TableCell sx={{ mb: 1, color: '#c62828', bgcolor: '#ffebee' }} align="right">Monto</TableCell>
                      <TableCell sx={{ mb: 1, color: '#c62828', bgcolor: '#ffebee' }} align="center">Eliminar</TableCell>
                    </TableRow>
                  </TableHead>
                  <TableBody>
                    {gastos.length === 0 ? (
                      <TableRow><TableCell colSpan={5} align="center">Sin gastos registrados</TableCell></TableRow>
                    ) : gastos.map(g => (
                      <TableRow key={g.id}>
                        <TableCell>{g.fecha?.split('T')[0]}</TableCell>
                        <TableCell>{g.descripcion || '-'}</TableCell>
                        <TableCell><Chip label={g.categoria_nombre || '-'} size="small" /></TableCell>
                        <TableCell align="right" sx={{ color: '#c62828', fontWeight: 'bold' }}>{fmt(g.monto)}</TableCell>
                        <TableCell align="center">
                          <IconButton size="small" onClick={() => deleteGasto(g.id)} color="error"><DeleteIcon fontSize="small" /></IconButton>
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </TableContainer>
            </Box>
          )}


          {/*Grafica*/}
          {tab === 3 && (
            <Box sx={{ p: 3, display: 'flex', flexDirection: 'column', alignItems: 'center', mt: 2 }}>
              <Typography variant="h6" gutterBottom>Gastos por Categoría</Typography>

              <Box
                sx={{
                  width: 300,
                  height: 300,
                  borderRadius: '50%',
                  background: totalGastos > 0 ? `conic-gradient(${etiquetas
                  .map((cat, i) => {
                  const colorPalette = ['#f44336', '#2196f3', '#ff9800', '#4caf50', '#9c27b0', '#00bcd4', '#f492ff', '#fff537'];
                  const color = colorPalette[i % colorPalette.length];
                  const start = i === 0 ? 0 : valores.slice(0, i).reduce((a, b) => a + b, 0);
                  const end = start + valores[i];
                  const startPercent = (start / totalGastos) * 100;
                  const endPercent = (end / totalGastos) * 100;
                  return `${color} ${startPercent}% ${endPercent}%`;
                  }).join(',')})`
                  : '#e0e0e0', 
                  }}
                />

          {/* Información de la grafica */}
          <Box sx={{ mt: 3, display: 'flex', flexWrap: 'wrap', gap: 2 }}>
            {etiquetas.map((cat, i) => (
              <Box key={cat} sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                <Box sx={{ width: 16, height: 16, bgcolor: ['#f44336', '#2196f3', '#ff9800', '#4caf50', '#9c27b0', '#00bcd4', '#f492ff', '#fff537'][i % 8] }} />
                <Typography variant="body2">{cat}: {valores[i].toLocaleString('es-DO', { style: 'currency', currency: 'DOP' })}</Typography>
                </Box>
              ))}
          </Box>


            <Divider sx={{ my: 10, width: '100%' }}>
              <Typography variant="caption">Grafica de barra</Typography>
            </Divider>

            {/* Selector del año */}
            <FormControl sx={{ mt: 2, mb: 3, minWidth: 120 }}>
              <InputLabel>Año</InputLabel>
              <Select
                value={anioSeleccionado}
                label="Año"
                onChange={e => setAnioSeleccionado(Number(e.target.value))}
                >
                {[2024, 2025, 2026, 2027, 2028, 2029, 2030, 2031, 2032].map(a => (
                  <MenuItem key={a} value={a}>{a}</MenuItem>
                  ))}
              </Select>
            </FormControl>

           {/* GASTOS POR MES */}
          <Box sx={{ mt: 0, width: '100%' }}>
            <Typography variant="h6" gutterBottom>
              Gastos de ({anioSeleccionado})
            </Typography>

          {/* Gráfico de barras */}
          <Box sx={{ display: 'flex', alignItems: 'flex-end', gap: 1, height: 200 }}>
            {gastosPorMes.map((valor, i) => (
              <Box key={i} sx={{ flex: 1, textAlign: 'center' }}>

                <Box
                  sx={{
                    height: valor > 0 ? `${(valor / max) * 180}px` : '2px',
                    bgcolor: '#c81505',
                    borderRadius: 1,
                    }}
                />

                <Typography variant="caption">{meses[i]}</Typography>
              </Box>
            ))}
          </Box>

          {/* Informacion de las barras */}
          <Box sx={{ mt: 3, display: 'flex', flexWrap: 'wrap', gap: 2 }}>
            {gastosPorMes.map((valor, i) => (
              <Box key={i} sx={{ display: 'flex', gap: 0.5 }}>
                <Typography variant="body2" fontWeight="bold">
                  {meses[i]}:
                </Typography>
                <Typography variant="body2">
                  {valor.toLocaleString('es-DO', { style: 'currency', currency: 'DOP' })}
                </Typography>
              </Box>
            ))}
          </Box>
        </Box>


        {/*Barras para ingresos*/}
        <Box sx={{ mt: 6, width: '100%' }}>
          <Typography variant="h6" gutterBottom>
            Ingresos de ({anioSeleccionado})
          </Typography>

        {/* Gráfico de barras */}
        <Box sx={{ display: 'flex', alignItems: 'flex-end', gap: 1, height: 200 }}>
          {ingresosPorMes.map((valor, i) => (
            <Box key={i} sx={{ flex: 1, textAlign: 'center' }}>

              <Box
                sx={{
                  height: valor > 0 ? `${(valor / maxIngresos) * 180}px` : '2px',
                  bgcolor: '#2e7d32', // verde = ingresos
                  borderRadius: 1,
                }}
              />
              <Typography variant="caption">{meses[i]}</Typography>
            </Box>
          ))}
        </Box>

        {/* Info */}
        <Box sx={{ mt: 3, display: 'flex', flexWrap: 'wrap', gap: 2 }}>
          {ingresosPorMes.map((valor, i) => (
            <Box key={i} sx={{ display: 'flex', gap: 0.5 }}>
              <Typography variant="body2" fontWeight="bold">
                {meses[i]}:
              </Typography>
              <Typography variant="body2">
                {valor.toLocaleString('es-DO', { style: 'currency', currency: 'DOP' })}
              </Typography>
            </Box>
          ))}
        </Box>
      </Box>
        </Box>
        )}

        </Paper>
      </Container>
    </Box>
  );
};

export default Dashboard;
